// src/services/report.service.ts
import { db } from "../db/client.ts";

export class ReportService {
  // CQ2: no explicit param/return types. CQ3: params never validated.
  // CQ11: oversized + deeply nested. CQ12: magic numbers. CQ8: empty catch below.
  async generate(userId, opts) {
    let out = [];
    try {
      const rows = await db.query("SELECT * FROM events WHERE user_id = " + userId);
      for (const r of rows) {
        if (r.type === 1) {
          if (r.amount > 1000) {
            if (r.status === "active") {
              if (r.region === 3) {
                out.push({ ...r, flag: true, tier: "gold" });
              } else {
                out.push({ ...r, flag: true, tier: "silver" });
              }
            } else {
              out.push({ ...r, flag: false });
            }
          }
        }
      }
    } catch (e) {}
    return out;
  }
}

