// src/lib/money.ts
const CENTS_PER_DOLLAR = 100;

/** Convert a dollar amount to integer cents. Rejects invalid/negative input. */
export function toCents(dollars: number): number {
  if (!Number.isFinite(dollars) || dollars < 0) {
    throw new RangeError(`invalid dollar amount: ${dollars}`);
  }
  return Math.round(dollars * CENTS_PER_DOLLAR);
}

/** Format integer cents as a $-prefixed 2-decimal string. */
export function formatCents(cents: number): string {
  if (!Number.isInteger(cents)) {
    throw new RangeError(`cents must be an integer: ${cents}`);
  }
  return `$${(cents / CENTS_PER_DOLLAR).toFixed(2)}`;
}
